// ScanBenchUser is a zero-reflection scanner for BenchUser.
// This is what would be generated by genus generate-scanners.
func ScanBenchUser(rows *sql.Rows) (BenchUser, error) {
	var u BenchUser
	err := rows.Scan(&u.ID, &u.Name, &u.Email, &u.Age, &u.IsActive, &u.Score)
	return u, err
}

func init() {
	// Register the scan function for BenchUser
	query.RegisterScanFunc[BenchUser](ScanBenchUser)
}

// BenchUser model that works with both GORM and Genus
type BenchUser struct {
	ID       int64  `gorm:"primaryKey;autoIncrement" db:"id"`
	Name     string `gorm:"column:name" db:"name"`
	Email    string `gorm:"column:email" db:"email"`
	Age      int    `gorm:"column:age" db:"age"`
	IsActive bool   `gorm:"column:is_active" db:"is_active"`
	Score    int    `gorm:"column:score" db:"score"`
}

func (BenchUser) TableName() string { return "users" }

var BenchUserFields = struct {
	ID       query.IntField
	Name     query.StringField
	Email    query.StringField
	Age      query.IntField
	IsActive query.BoolField
	Score    query.IntField
}{
	ID:       query.NewIntField("id"),
	Name:     query.NewStringField("name"),
	Email:    query.NewStringField("email"),
	Age:      query.NewIntField("age"),
	IsActive: query.NewBoolField("is_active"),
	Score:    query.NewIntField("score"),
}

// ============================================================================
// Setup Functions
// ============================================================================

func setupGormDB(b *testing.B) (*gorm.DB, func()) {
	db, err := gorm.Open(sqlite.Open(":memory:"), &gorm.Config{
		Logger:                 logger.Default.LogMode(logger.Silent),
		SkipDefaultTransaction: true, // Important for fair comparison
	})
	if err != nil {
		b.Fatal(err)
	}

	sqlDB, _ := db.DB()

	// Create table and insert data
	sqlDB.Exec(`CREATE TABLE users (
		id INTEGER PRIMARY KEY AUTOINCREMENT,
		name TEXT, email TEXT, age INTEGER,
		is_active BOOLEAN, score INTEGER,
		created_at DATETIME, updated_at DATETIME
	)`)

	stmt, _ := sqlDB.Prepare("INSERT INTO users (name, email, age, is_active, score) VALUES (?, ?, ?, ?, ?)")
	for i := 0; i < 1000; i++ {
		stmt.Exec(fmt.Sprintf("User %d", i), fmt.Sprintf("user%d@example.com", i), 20+(i%50), i%2 == 0, i*10)
	}
	stmt.Close()

	return db, func() { sqlDB.Close() }
}

func setupGenusDB(b *testing.B) (*genus.Genus, *sql.DB, func()) {
	sqlDB, err := sql.Open("sqlite3", ":memory:")
	if err != nil {
		b.Fatal(err)
	}

	sqlDB.Exec(`CREATE TABLE users (
		id INTEGER PRIMARY KEY AUTOINCREMENT,
		name TEXT, email TEXT, age INTEGER,
		is_active BOOLEAN, score INTEGER,
		created_at DATETIME, updated_at DATETIME
	)`)

	stmt, _ := sqlDB.Prepare("INSERT INTO users (name, email, age, is_active, score) VALUES (?, ?, ?, ?, ?)")
	for i := 0; i < 1000; i++ {
		stmt.Exec(fmt.Sprintf("User %d", i), fmt.Sprintf("user%d@example.com", i), 20+(i%50), i%2 == 0, i*10)
	}
	stmt.Close()

	db := genus.NewWithLogger(sqlDB, dialects.DetectDialect("sqlite3"), &core.NoOpLogger{})
	return db, sqlDB, func() { sqlDB.Close() }
}

// ============================================================================
// SELECT ALL (500 rows) - The most common operation
// ============================================================================

func BenchmarkSelectAll_GORM(b *testing.B) {
	db, cleanup := setupGormDB(b)
	defer cleanup()

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		var users []BenchUser
		db.Where("is_active = ?", true).Find(&users)
	}
}

func BenchmarkSelectAll_Genus(b *testing.B) {
	db, _, cleanup := setupGenusDB(b)
	defer cleanup()
	ctx := context.Background()

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		_, _ = genus.Table[BenchUser](db).
			Where(BenchUserFields.IsActive.Eq(true)).
			Find(ctx)
	}
}

