func BenchmarkSelectAll_GenusPrepared(b *testing.B) {
	db, _, cleanup := setupGenusDB(b)
	defer cleanup()
	ctx := context.Background()

	// Create prepared query once
	pq := query.PrepareSelectAll[BenchUser](
		db.DB().Executor(),
		db.DB().Dialect(),
		"users",
		[]string{"id", "name", "email", "age", "is_active", "score"},
		[]string{"is_active"},
	)

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		_, _ = pq.Exec(ctx, true)
	}
}

func BenchmarkSelectAll_RawSQL(b *testing.B) {
	_, sqlDB, cleanup := setupGenusDB(b)
	defer cleanup()
	ctx := context.Background()

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		rows, _ := sqlDB.QueryContext(ctx, "SELECT id, name, email, age, is_active, score FROM users WHERE is_active = ?", true)
		var users []BenchUser
		for rows.Next() {
			var u BenchUser
			rows.Scan(&u.ID, &u.Name, &u.Email, &u.Age, &u.IsActive, &u.Score)
			users = append(users, u)
		}
		rows.Close()
	}
}

func BenchmarkSelectAll_RawSQL_Prealloc(b *testing.B) {
	_, sqlDB, cleanup := setupGenusDB(b)
	defer cleanup()
	ctx := context.Background()

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		rows, _ := sqlDB.QueryContext(ctx, "SELECT id, name, email, age, is_active, score FROM users WHERE is_active = ?", true)
		users := make([]BenchUser, 0, 512)
		for rows.Next() {
			var u BenchUser
			rows.Scan(&u.ID, &u.Name, &u.Email, &u.Age, &u.IsActive, &u.Score)
			users = append(users, u)
		}
		rows.Close()
		_ = users
	}
}

