func BenchmarkUpdate_GORM(b *testing.B) {
	db, cleanup := setupGormDB(b)
	defer cleanup()

	var user BenchUser
	db.First(&user)

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		user.Score = i
		db.Save(&user)
	}
}

func BenchmarkUpdate_Genus(b *testing.B) {
	db, _, cleanup := setupGenusDB(b)
	defer cleanup()
	ctx := context.Background()

	user, _ := genus.Table[BenchUser](db).First(ctx)

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		user.Score = i
		db.DB().Update(ctx, &user)
	}
}

func BenchmarkUpdate_RawSQL(b *testing.B) {
	_, sqlDB, cleanup := setupGenusDB(b)
	defer cleanup()
	ctx := context.Background()

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		sqlDB.ExecContext(ctx, "UPDATE users SET score = ? WHERE id = ?", i, 1)
	}
}

// ============================================================================
// COMPLEX QUERY (5 conditions + ORDER + LIMIT)
// ============================================================================

func BenchmarkComplex_GORM(b *testing.B) {
	db, cleanup := setupGormDB(b)
	defer cleanup()

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		var users []BenchUser
		db.Where("is_active = ?", true).
			Where("age >= ?", 25).
			Where("age <= ?", 40).
			Where("score > ?", 100).
			Where("name LIKE ?", "%User%").
			Order("score").
			Limit(10).
			Find(&users)
	}
}

func BenchmarkComplex_Genus(b *testing.B) {
	db, _, cleanup := setupGenusDB(b)
	defer cleanup()
	ctx := context.Background()

	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		_, _ = genus.Table[BenchUser](db).
			Where(BenchUserFields.IsActive.Eq(true)).
			Where(BenchUserFields.Age.Gte(25)).
			Where(BenchUserFields.Age.Lte(40)).
			Where(BenchUserFields.Score.Gt(100)).
			Where(BenchUserFields.Name.Like("%User%")).
			OrderByAsc("score").
			Limit(10).
			Find(ctx)
	}
}

